import React, { useState } from 'react'

function ColorSwatch({ color }) {
  if (!Array.isArray(color) || color.length < 3) return null
  const [r, g, b] = color.map(v => Math.round(v * 255))
  return (
    <span style={{
      display: 'inline-block', width: 12, height: 12, borderRadius: 2,
      background: `rgb(${r},${g},${b})`, border: '1px solid #444',
      verticalAlign: 'middle', marginRight: 6,
    }} />
  )
}

function ObjectCard({ obj }) {
  const [open, setOpen] = useState(false)
  const mat = obj.material || {}
  const typeColors = {
    cylinder: '#4a9eff', sphere: '#ff7c4a', cube: '#4aff9e',
    torus: '#ff4af0', metaball: '#ffd44a', cone: '#4affec',
    plane: '#a0a0a0', imported_glb: '#ff4a6e',
  }
  const typeColor = typeColors[obj.type] || '#888'

  return (
    <div style={styles.card}>
      <div style={styles.cardHeader} onClick={() => setOpen(o => !o)}>
        <span style={{ ...styles.typeBadge, borderColor: typeColor, color: typeColor }}>
          {obj.type}
        </span>
        <span style={styles.objId}>{obj.id}</span>
        {obj.parent && <span style={styles.parentTag}>⤴ {obj.parent}</span>}
        {mat.base_color && <ColorSwatch color={mat.base_color} />}
        <span style={styles.chevron}>{open ? '▲' : '▼'}</span>
      </div>

      {open && (
        <div style={styles.cardBody}>
          {obj.name && <Row label="name" value={obj.name} />}
          <Row label="position" value={fmtVec(obj.position)} />
          {obj.rotation_euler?.some(v => v !== 0) &&
            <Row label="rotation" value={fmtVec(obj.rotation_euler)} />}
          {obj.params && Object.entries(obj.params).map(([k, v]) => (
            <Row key={k} label={k} value={JSON.stringify(v)} />
          ))}
          {obj.metaball_group && <Row label="metaball_group" value={obj.metaball_group} />}
          {mat.base_color && (
            <Row label="color"
              value={<><ColorSwatch color={mat.base_color} />{fmtColor(mat.base_color)}</>} />
          )}
          {mat.roughness !== undefined && <Row label="roughness" value={mat.roughness.toFixed(2)} />}
          {mat.metallic !== undefined && <Row label="metallic" value={mat.metallic.toFixed(2)} />}
        </div>
      )}
    </div>
  )
}

function Row({ label, value }) {
  return (
    <div style={styles.row}>
      <span style={styles.rowLabel}>{label}</span>
      <span style={styles.rowValue}>{value}</span>
    </div>
  )
}

function fmtVec(v) {
  if (!Array.isArray(v)) return '—'
  return `[${v.map(n => (typeof n === 'number' ? n.toFixed(2) : n)).join(', ')}]`
}

function fmtColor(c) {
  if (!Array.isArray(c)) return ''
  const [r, g, b] = c.map(v => Math.round(v * 255))
  return `rgb(${r}, ${g}, ${b})`
}

export default function SceneGraph({ sceneGraph }) {
  if (!sceneGraph) {
    return (
      <div style={styles.empty}>
        Generate a scene to see its graph here.
      </div>
    )
  }

  const objects = sceneGraph.objects || []
  const typeGroups = objects.reduce((acc, obj) => {
    const t = obj.type || 'unknown'
    acc[t] = (acc[t] || 0) + 1
    return acc
  }, {})

  return (
    <div style={styles.root}>
      {/* Summary bar */}
      <div style={styles.summary}>
        <span style={styles.summaryTitle}>{sceneGraph.description || 'Scene'}</span>
        <div style={styles.pills}>
          {Object.entries(typeGroups).map(([type, count]) => (
            <span key={type} style={styles.pill}>{type} ×{count}</span>
          ))}
        </div>
      </div>

      {/* Object cards */}
      <div style={styles.list}>
        {objects.map((obj, i) => <ObjectCard key={obj.id || i} obj={obj} />)}
      </div>

      {/* Raw JSON toggle */}
      <details style={styles.rawSection}>
        <summary style={styles.rawToggle}>Raw JSON</summary>
        <pre style={styles.rawJson}>{JSON.stringify(sceneGraph, null, 2)}</pre>
      </details>
    </div>
  )
}

const styles = {
  root: { flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' },
  empty: {
    flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center',
    color: '#555', fontSize: 14,
  },
  summary: {
    padding: '12px 16px', borderBottom: '1px solid #2a2a3a',
    background: '#16161e', flexShrink: 0,
  },
  summaryTitle: { fontSize: 13, fontWeight: 600, display: 'block', marginBottom: 6 },
  pills: { display: 'flex', flexWrap: 'wrap', gap: 6 },
  pill: {
    fontSize: 11, padding: '2px 8px', borderRadius: 4,
    background: '#2a2a3a', color: '#a0a0b0',
  },
  list: { flex: 1, overflowY: 'auto', padding: '10px 12px', display: 'flex', flexDirection: 'column', gap: 6 },
  card: { background: '#16161e', borderRadius: 8, border: '1px solid #2a2a3a', overflow: 'hidden' },
  cardHeader: {
    display: 'flex', alignItems: 'center', gap: 8, padding: '8px 12px',
    cursor: 'pointer', userSelect: 'none',
  },
  typeBadge: {
    fontSize: 10, padding: '1px 6px', borderRadius: 4, border: '1px solid',
    fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.04em', flexShrink: 0,
  },
  objId: { flex: 1, fontSize: 12, fontWeight: 600, color: '#c0c0d0' },
  parentTag: { fontSize: 10, color: '#666', flexShrink: 0 },
  chevron: { color: '#555', fontSize: 10, flexShrink: 0 },
  cardBody: { padding: '6px 12px 10px', borderTop: '1px solid #2a2a3a' },
  row: { display: 'flex', gap: 8, padding: '2px 0', alignItems: 'center' },
  rowLabel: { fontSize: 11, color: '#666', width: 100, flexShrink: 0 },
  rowValue: { fontSize: 11, color: '#a0b0c0', fontFamily: 'monospace' },
  rawSection: { borderTop: '1px solid #2a2a3a', flexShrink: 0 },
  rawToggle: {
    padding: '8px 16px', fontSize: 12, color: '#555', cursor: 'pointer',
    userSelect: 'none', background: '#16161e',
  },
  rawJson: {
    fontSize: 11, overflowX: 'auto', padding: '12px 16px',
    background: '#0a0a10', color: '#7c9', maxHeight: 300, overflowY: 'auto',
  },
}

